package kotlinx.datetime.test

import kotlinx.datetime.*
import kotlinx.datetime.format.*
import kotlin.test.*

/**
 * Tests for consistent parsing behavior of Instant across all platforms.
 * This addresses the issue where JVM/JS allowed omitting seconds while native (iOS) did not.
 */
class InstantParseConsistencyTest {

    @Test
    fun testParseWithSecondsRequired() {
        // According to ISO_DATE_TIME_OFFSET documentation, seconds are NOT optional
        // This should work on all platforms
        val validInstant = "2024-03-19T17:50:00Z"
        val parsed = Instant.parse(validInstant)
        assertNotNull(parsed)
        assertEquals(2024, parsed.toLocalDateTime(TimeZone.UTC).year)
        assertEquals(3, parsed.toLocalDateTime(TimeZone.UTC).monthNumber)
        assertEquals(19, parsed.toLocalDateTime(TimeZone.UTC).dayOfMonth)
        assertEquals(17, parsed.toLocalDateTime(TimeZone.UTC).hour)
        assertEquals(50, parsed.toLocalDateTime(TimeZone.UTC).minute)
        assertEquals(0, parsed.toLocalDateTime(TimeZone.UTC).second)
    }

    @Test
    fun testParseWithoutSecondsShouldFail() {
        // Omitting seconds should fail on all platforms (was inconsistent before the fix)
        val invalidInstant = "2024-03-19T17:50Z"
        assertFailsWith<DateTimeFormatException> {
            Instant.parse(invalidInstant)
        }
    }

    @Test
    fun testParseWithSecondsAndFractionalSeconds() {
        // Should work with fractional seconds
        val validInstant = "2024-03-19T17:50:30.123Z"
        val parsed = Instant.parse(validInstant)
        assertNotNull(parsed)
        assertEquals(30, parsed.toLocalDateTime(TimeZone.UTC).second)
        assertEquals(123_000_000, parsed.nanosecondsOfSecond)
    }

    @Test
    fun testParseWithOffset() {
        // Should work with various offsets
        val validInstant = "2024-03-19T17:50:00+03:00"
        val parsed = Instant.parse(validInstant)
        assertNotNull(parsed)
        // The instant should be adjusted to UTC
        assertEquals(14, parsed.toLocalDateTime(TimeZone.UTC).hour) // 17 - 3 = 14
    }

    @Test
    fun testParseWithOffsetNoMinutes() {
        // According to documentation, omitting offset minutes is allowed (e.g., +03 instead of +03:00)
        val validInstant = "2024-03-19T17:50:00+03"
        val parsed = Instant.parse(validInstant)
        assertNotNull(parsed)
        assertEquals(14, parsed.toLocalDateTime(TimeZone.UTC).hour) // 17 - 3 = 14
    }

    @Test
    fun testParseWithOffsetButNoSecondsShouldFail() {
        // Even with offset, seconds should be required
        val invalidInstant = "2024-03-19T17:50+03:00"
        assertFailsWith<DateTimeFormatException> {
            Instant.parse(invalidInstant)
        }
    }

    @Test
    fun testParseWithComponentsFormat() {
        // Test using DateTimeComponents.Formats.ISO_DATE_TIME_OFFSET explicitly
        val validInstant = "2024-03-19T17:50:00Z"
        val parsed = Instant.parse(validInstant, DateTimeComponents.Formats.ISO_DATE_TIME_OFFSET)
        assertNotNull(parsed)
        assertEquals(17, parsed.toLocalDateTime(TimeZone.UTC).hour)
        assertEquals(50, parsed.toLocalDateTime(TimeZone.UTC).minute)
        assertEquals(0, parsed.toLocalDateTime(TimeZone.UTC).second)
    }

    @Test
    fun testParseWithComponentsFormatNoSecondsShouldFail() {
        // Test that the explicit format also requires seconds
        val invalidInstant = "2024-03-19T17:50Z"
        assertFailsWith<DateTimeFormatException> {
            Instant.parse(invalidInstant, DateTimeComponents.Formats.ISO_DATE_TIME_OFFSET)
        }
    }
}
"}

