{"file_path": "/project/test_instant_parse.kt", "content": "import kotlinx.datetime.*

fun main() {
    println("Testing Instant.parse() behavior:")

    // Test 1: Valid string with seconds - should work
    try {
        val instant1 = Instant.parse("2024-03-19T17:50:00Z")
        println("✓ Successfully parsed: 2024-03-19T17:50:00Z")
        println("  Result: $instant1")
    } catch (e: Exception) {
        println("✗ Failed to parse: 2024-03-19T17:50:00Z")
        println("  Error: ${e.message}")
    }

    // Test 2: Invalid string without seconds - should fail
    try {
        val instant2 = Instant.parse("2024-03-19T17:50Z")
        println("✗ Incorrectly parsed: 2024-03-19T17:50Z (should have failed)")
        println("  Result: $instant2")
    } catch (e: DateTimeFormatException) {
        println("✓ Correctly rejected: 2024-03-19T17:50Z")
        println("  Error: ${e.message}")
    }

    // Test 3: Valid string with offset and seconds
    try {
        val instant3 = Instant.parse("2024-03-19T17:50:00+03:00")
        println("✓ Successfully parsed: 2024-03-19T17:50:00+03:00")
        println("  Result: $instant3")
    } catch (e: Exception) {
        println("✗ Failed to parse: 2024-03-19T17:50:00+03:00")
        println("  Error: ${e.message}")
    }

    // Test 4: Valid string with offset (no offset minutes) and seconds
    try {
        val instant4 = Instant.parse("2024-03-19T17:50:00+03")
        println("✓ Successfully parsed: 2024-03-19T17:50:00+03")
        println("  Result: $instant4")
    } catch (e: Exception) {
        println("✗ Failed to parse: 2024-03-19T17:50:00+03")
        println("  Error: ${e.message}")
    }

    println("\nAll platforms should now behave consistently!")
}
"}

